  Log logger = LogFactory.getLog("org.ascension.sailpoint.attestation.psattestation");
  
  List<IdentityHistoryItem> iiList = new ArrayList();
  public void createFile(IdentityHistoryItem object) throws GeneralException, IOException
  {
    String fileSeparator = System.getProperty("file.separator");
    String dirPath = "D:/temp/IdentityHistoriesBackup";
    Path dirPathObj = Paths.get(dirPath);
    boolean dirExists = Files.exists(dirPathObj);

    if (dirExists)
    {
      System.out.println("! Directory Already Exists !    " + dirPathObj);
    }
    else
    {
      try
      {
        // Creating The New Directory Structure
        Files.createDirectories(dirPathObj);
        System.out.println("! New Directory Successfully Created !   " + dirPathObj);
      }
      catch (IOException ioExceptionObj)
      {
        System.out
          .println("Problem Occured While Creating The Directory Structure= " + ioExceptionObj.getMessage());
      }
    }

    String fileData = object.toXml();
    Files.write(Paths.get(dirPathObj + fileSeparator + object.getAccount() + ".xml"), fileData.getBytes());
  }


  public String updateIdentityHistory() throws GeneralException, IOException
