    query.addFilter(Filter.and(Filter.eq("status", "Remediated"),Filter.eq("application", "PeopleSoft Attestation")));
    Iterator itr = context.search(IdentityHistoryItem.class, query);
    while(itr.hasNext())
    {
      IdentityHistoryItem item = itr.next();
      createFile(item);
      CertificationAction action = item.getAction();
      action.setRemediationCompleted(true);
      action.setCompletionState(State.Finished);
      iiList.add(item);
      context.saveObject(item);
     /* if(count >= 100)
      {
